import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import hospitalService from '../../services/hospitalService';
import HospitalCard from '../../components/hospitals/HospitalCard';
import HospitalStatusBadge from '../../components/hospitals/HospitalStatusBadge';
import { useAuth } from '../../context/AuthContext';

function HospitalListPage() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const isSuperAdmin = user?.role === 'SUPER_ADMIN';

  const [hospitals, setHospitals]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [search, setSearch]         = useState('');
  const [filterType, setFilterType] = useState('');
  const [rejectModal, setRejectModal] = useState({ open: false, hospital: null });
  const [rejectReason, setRejectReason] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const fetchHospitals = async () => {
    setLoading(true);
    try {
      const params = {};
      if (search)     params.search        = search;
      if (filterType) params.hospital_type = filterType;
      const data = isSuperAdmin
        ? await hospitalService.getPendingHospitals()
        : await hospitalService.listHospitals(params);
      setHospitals(data.data || []);
    } catch {
      toast.error('Failed to load hospitals.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchHospitals(); }, [search, filterType]);

  const handleApprove = async (hospital) => {
    setActionLoading(true);
    try {
      await hospitalService.approveReject(hospital.id, 'approve');
      toast.success(`${hospital.hospital_name} approved!`);
      fetchHospitals();
    } catch {
      toast.error('Action failed.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleRejectSubmit = async () => {
    if (!rejectReason.trim()) return toast.error('Rejection reason is required.');
    setActionLoading(true);
    try {
      await hospitalService.approveReject(rejectModal.hospital.id, 'reject', rejectReason);
      toast.success(`${rejectModal.hospital.hospital_name} rejected.`);
      setRejectModal({ open: false, hospital: null });
      setRejectReason('');
      fetchHospitals();
    } catch {
      toast.error('Action failed.');
    } finally {
      setActionLoading(false);
    }
  };

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-5">
        <div>
          <h1 className="text-lg font-bold text-gray-900">
            {isSuperAdmin ? 'Pending Hospital Approvals' : 'Hospitals'}
          </h1>
          <p className="text-xs text-gray-500 mt-0.5">
            {isSuperAdmin ? 'Review and approve hospital registrations' : 'Browse all approved hospitals'}
          </p>
        </div>
        {user?.role === 'HOSPITAL_ADMIN' && (
          <button onClick={() => navigate('/hospital/register')}
            className="px-4 py-2 text-xs font-medium text-white bg-blue-600 rounded-lg
                       hover:bg-blue-700 transition-colors">
            + Register Hospital
          </button>
        )}
      </div>

      {/* Filters (non-admin only) */}
      {!isSuperAdmin && (
        <div className="flex gap-3 mb-5">
          <input
            value={search} onChange={e => setSearch(e.target.value)}
            placeholder="Search hospitals..."
            className="flex-1 px-3 py-2 text-sm border border-gray-300 rounded-lg
                       focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
          <select value={filterType} onChange={e => setFilterType(e.target.value)}
            className="px-3 py-2 text-sm border border-gray-300 rounded-lg
                       focus:outline-none focus:ring-2 focus:ring-blue-500">
            <option value="">All Types</option>
            <option value="GENERAL">General</option>
            <option value="MULTI_SPECIALTY">Multi-Speciality</option>
            <option value="CLINIC">Clinic</option>
            <option value="DIAGNOSTIC">Diagnostic</option>
          </select>
        </div>
      )}

      {/* Content */}
      {loading ? (
        <div className="flex items-center justify-center py-20">
          <svg className="animate-spin w-8 h-8 text-blue-500" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
          </svg>
        </div>
      ) : hospitals.length === 0 ? (
        <div className="text-center py-20">
          <div className="w-14 h-14 mx-auto mb-4 bg-gray-100 rounded-full flex items-center justify-center">
            <svg className="w-7 h-7 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5}
                d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16" />
            </svg>
          </div>
          <p className="text-sm font-medium text-gray-600">No hospitals found</p>
          <p className="text-xs text-gray-400 mt-1">
            {isSuperAdmin ? 'No pending approvals at the moment.' : 'Try adjusting your search.'}
          </p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {hospitals.map(hospital => (
            <HospitalCard
              key={hospital.id}
              hospital={hospital}
              showStatus={isSuperAdmin}
              actions={isSuperAdmin && (
                <>
                  <button
                    onClick={() => handleApprove(hospital)}
                    disabled={actionLoading}
                    className="px-3 py-1 text-xs font-medium text-white bg-green-600
                               rounded-md hover:bg-green-700 transition-colors disabled:opacity-50"
                  >
                    Approve
                  </button>
                  <button
                    onClick={() => setRejectModal({ open: true, hospital })}
                    disabled={actionLoading}
                    className="px-3 py-1 text-xs font-medium text-white bg-red-600
                               rounded-md hover:bg-red-700 transition-colors disabled:opacity-50"
                  >
                    Reject
                  </button>
                </>
              )}
            />
          ))}
        </div>
      )}

      {/* Reject Modal */}
      {rejectModal.open && (
        <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-md p-6">
            <h3 className="text-sm font-bold text-gray-900 mb-1">Reject Hospital</h3>
            <p className="text-xs text-gray-500 mb-4">
              Rejecting: <strong>{rejectModal.hospital?.hospital_name}</strong>
            </p>
            <label className="block text-xs font-medium text-gray-700 mb-1">
              Reason for Rejection *
            </label>
            <textarea
              value={rejectReason}
              onChange={e => setRejectReason(e.target.value)}
              rows={4}
              className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg
                         focus:outline-none focus:ring-2 focus:ring-red-400"
              placeholder="Explain why this hospital is being rejected..."
            />
            <div className="flex justify-end gap-3 mt-4">
              <button
                onClick={() => { setRejectModal({ open: false, hospital: null }); setRejectReason(''); }}
                className="px-4 py-2 text-xs font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200"
              >
                Cancel
              </button>
              <button
                onClick={handleRejectSubmit}
                disabled={actionLoading}
                className="px-4 py-2 text-xs font-medium text-white bg-red-600 rounded-lg
                           hover:bg-red-700 disabled:opacity-50"
              >
                {actionLoading ? 'Rejecting...' : 'Confirm Reject'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default HospitalListPage;
